import { useState, useEffect } from 'react';
import { supabase } from '../supabaseClient';
import type {
  Document,
  DocumentFormData,
  DocumentStatus
} from '../components/Documents/document';
import {
  STATUS_TO_STEP,
  STATUS_TO_PROGRESS
} from '../components/Documents/document';

export function useDocuments() {
  const [documents, setDocuments] = useState<Document[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [documentVersions, setDocumentVersions] = useState<any[]>([]);

  // ======================
  // CHARGEMENT DES DOCUMENTS
  // ======================
  const fetchDocuments = async () => {
    try {
      setLoading(true);
      const { data, error } = await supabase
        .from('documents')
        .select('*')
        .order('created_at', { ascending: false });

      if (error) throw error;
      setDocuments(data || []);
      setError(null);
    } catch (err) {
      console.error('Erreur chargement documents:', err);
      setError(err instanceof Error ? err.message : 'Erreur inconnue');
    } finally {
      setLoading(false);
    }
  };

  // ======================
  // FILTRAGE DES DOCUMENTS
  // ======================
  const filterDocuments = async (
    searchTerm: string = '',
    statusFilter: string = 'Tous',
    typeFilter: string = 'Tous'
  ) => {
    try {
      setLoading(true);

      let query = supabase
        .from('documents')
        .select('*')
        .order('created_at', { ascending: false });

      if (searchTerm) {
        const searchLower = searchTerm.toLowerCase();
        query = query.or(
          `title.ilike.%${searchLower}%,source.ilike.%${searchLower}%`
        );
      }

      if (statusFilter !== 'Tous') {
        query = query.eq('status', statusFilter);
      }

      if (typeFilter !== 'Tous') {
        query = query.eq('type', typeFilter);
      }

      const { data, error } = await query;

      if (error) throw error;
      setDocuments(data || []);
      setError(null);
    } catch (err) {
      console.error('Erreur filtrage:', err);
      setError(err instanceof Error ? err.message : 'Erreur inconnue');
    } finally {
      setLoading(false);
    }
  };

  // ======================
  // CRÉATION DE DOCUMENT (CORRIGÉ getSession)
  // ======================
  const createDocument = async (documentData: DocumentFormData) => {
    try {
      const sessionResponse = await supabase.auth.getSession();
      const session = sessionResponse?.data?.session;

      if (!session?.user) {
        throw new Error("Session invalide");
      }

      const completeData = {
        ...documentData,
        status: documentData.status || 'imported',
        workflow_step: STATUS_TO_STEP[documentData.status || 'imported'],
        progress: STATUS_TO_PROGRESS[documentData.status || 'imported'],
        tags: documentData.tags || [],
        user_id: session.user.id
      };

      const { data, error } = await supabase
        .from('documents')
        .insert([completeData])
        .select()
        .single();

      if (error) throw error;

      setDocuments(prev => [data, ...prev]);
      return data;
    } catch (err) {
      console.error('Erreur création:', err);
      throw err;
    }
  };

  // ======================
  // TRANSITION DE WORKFLOW (CORRIGÉ getSession)
  // ======================
  const advanceWorkflow = async (
    documentId: string,
    actionType: string,
    notes?: string
  ) => {
    try {
      const sessionResponse = await supabase.auth.getSession();
      const session = sessionResponse?.data?.session;

      if (!session?.user) {
        throw new Error("Session invalide");
      }

      const document = documents.find(d => d.id === documentId);
      if (!document) throw new Error("Document non trouvé");

      let newStatus: DocumentStatus;
      switch (actionType) {
        case 'start_transcription':
          newStatus = 'transcribing';
          break;
        case 'complete_transcription':
          newStatus = 'transcribed';
          break;
        case 'start_review':
          newStatus = 'book_project';
          break;
        case 'complete_review':
          newStatus = 'proofreading_1';
          break;
        case 'start_tagging':
          newStatus = 'proofreading_2';
          break;
        case 'complete_tagging':
          newStatus = 'edited';
          break;
        case 'start_editing':
          newStatus = 'proofreading_2';
          break;
        case 'complete_editing':
          newStatus = 'edited';
          break;
        case 'reopen_document':
          newStatus = 'book_project';
          break;
        default:
          throw new Error(`Action invalide: ${actionType}`);
      }

      // Créer une version avant la transition
      await updateDocumentWithVersioning(documentId, {
        status: newStatus,
        workflow_step: STATUS_TO_STEP[newStatus],
        progress: STATUS_TO_PROGRESS[newStatus]
      });

      // Enregistrer l'action dans workflow_actions
      await supabase
        .from('workflow_actions')
        .insert([{
          document_id: documentId,
          action_type: actionType,
          from_status: document.status,
          to_status: newStatus,
          performed_by: session.user.id,
          notes: notes || null
        }]);

      return { success: true, newStatus };
    } catch (err) {
      console.error('Erreur transition workflow:', err);
      throw err;
    }
  };

  // ======================
  // MISE À JOUR AVEC VERSIONING (CORRIGÉ - workflow_step présent dans document_versions)
  // ======================
  const updateDocumentWithVersioning = async (
    documentId: string,
    updates: Partial<DocumentFormData>
  ) => {
    try {
      const sessionResponse = await supabase.auth.getSession();
      const session = sessionResponse?.data?.session;

      if (!session?.user) {
        throw new Error("Session invalide");
      }

      // 1. Récupérer document courant
      const { data: currentDoc, error: fetchError } = await supabase
        .from('documents')
        .select('*')
        .eq('id', documentId)
        .single();
      if (fetchError) throw fetchError;

      // 2. Compter versions existantes
      const { count } = await supabase
        .from('document_versions')
        .select('*', { count: 'exact', head: true })
        .eq('document_id', documentId);
      const nextVersion = (count || 0) + 1;

      // 3. Sauvegarder version précédente (AVEC workflow_step)
      const versionData = {
        document_id: documentId,
        version_number: nextVersion,
        title: currentDoc.title,
        type: currentDoc.type,
        source: currentDoc.source,
        status: currentDoc.status,
        workflow_step: currentDoc.workflow_step, // ✅ Maintenant présent dans la table
        progress: currentDoc.progress,
        assigned_to: currentDoc.assigned_to,
        tags: currentDoc.tags,
        file_url: currentDoc.file_url || null,
        content: currentDoc.content || null,
        created_by: session.user.id,
        restored_from_version: null,
        restoration_reason: null
      };

      const { error: versionError } = await supabase
        .from('document_versions')
        .insert([versionData]);
      if (versionError) throw versionError;

      // 4. Calculer workflow_step et progress si status change
      let finalUpdates = { ...updates };
      if (updates.status) {
        finalUpdates = {
          ...updates,
          workflow_step: STATUS_TO_STEP[updates.status as DocumentStatus],
          progress: STATUS_TO_PROGRESS[updates.status as DocumentStatus]
        };
      }

      // 5. Mettre à jour document
      const { data: updatedDoc, error: updateError } = await supabase
        .from('documents')
        .update(finalUpdates)
        .eq('id', documentId)
        .select()
        .single();
      if (updateError) throw updateError;

      // 6. Mettre à jour état local
      setDocuments(prev =>
        prev.map(doc => doc.id === documentId ? { ...doc, ...updatedDoc } : doc)
      );

      return updatedDoc;
    } catch (err) {
      console.error('Erreur versioning:', err);
      throw err;
    }
  };

  // ======================
  // RÉCUPÉRATION DES VERSIONS
  // ======================
  const fetchDocumentVersions = async (documentId: string) => {
    try {
      const { data, error } = await supabase
        .from('document_versions')
        .select('*')
        .eq('document_id', documentId)
        .order('created_at', { ascending: false });

      if (error) throw error;
      setDocumentVersions(data || []);
      return data;
    } catch (err) {
      console.error('Erreur chargement versions:', err);
      throw err;
    }
  };

  // ======================
  // RESTAURATION DE VERSION
  // ======================
  const restoreDocumentVersion = async (
    documentId: string,
    versionId: string,
    restorationReason: string
  ) => {
    try {
      const sessionResponse = await supabase.auth.getSession();
      const session = sessionResponse?.data?.session;

      if (!session?.user) {
        throw new Error("Session invalide");
      }

      // 1. Récupérer la version à restaurer
      const { data: versionToRestore, error: versionError } = await supabase
        .from('document_versions')
        .select('*')
        .eq('id', versionId)
        .single();
      if (versionError) throw versionError;

      // 2. Sauvegarder l'état ACTUEL avant restauration
      const currentDoc = documents.find(d => d.id === documentId);
      if (currentDoc) {
        await updateDocumentWithVersioning(documentId, {
          title: currentDoc.title,
          type: currentDoc.type,
          source: currentDoc.source,
          status: currentDoc.status,
          workflow_step: currentDoc.workflow_step,
          progress: currentDoc.progress,
          assigned_to: currentDoc.assigned_to,
          tags: currentDoc.tags,
          file_url: currentDoc.file_url || '',
          content: currentDoc.content || ''
        });
      }

      // 3. Restaurer le document
      const { data: restoredDoc, error: restoreError } = await supabase
        .from('documents')
        .update({
          title: versionToRestore.title,
          type: versionToRestore.type,
          source: versionToRestore.source,
          status: versionToRestore.status,
          workflow_step: versionToRestore.workflow_step,
          progress: versionToRestore.progress,
          assigned_to: versionToRestore.assigned_to,
          tags: versionToRestore.tags,
          file_url: versionToRestore.file_url,
          content: versionToRestore.content,
          updated_at: new Date().toISOString()
        })
        .eq('id', documentId)
        .select()
        .single();
      if (restoreError) throw restoreError;

      // 4. Mettre à jour l'état local
      setDocuments(prev =>
        prev.map(doc => doc.id === documentId ? { ...doc, ...restoredDoc } : doc)
      );

      // 5. Recharger les versions
      await fetchDocumentVersions(documentId);

      return restoredDoc;
    } catch (err) {
      console.error('Erreur restauration:', err);
      throw err;
    }
  };

  // ======================
  // SUPPRESSION
  // ======================
  const deleteDocument = async (id: string) => {
    try {
      const { error } = await supabase
        .from('documents')
        .delete()
        .eq('id', id);

      if (error) throw error;

      setDocuments(prev => prev.filter(doc => doc.id !== id));
    } catch (err) {
      console.error('Erreur suppression:', err);
      throw err;
    }
  };

  const deleteDocuments = async (ids: string[]) => {
    try {
      const { error } = await supabase
        .from('documents')
        .delete()
        .in('id', ids);

      if (error) throw error;

      setDocuments(prev => prev.filter(doc => !ids.includes(doc.id)));
    } catch (err) {
      console.error('Erreur suppression multiple:', err);
      throw err;
    }
  };

  // ======================
  // REALTIME
  // ======================
  useEffect(() => {
    const channel = supabase
      .channel('documents-changes')
      .on(
        'postgres_changes',
        { event: '*', schema: 'public', table: 'documents' },
        () => {
          fetchDocuments();
        }
      )
      .subscribe();

    fetchDocuments();

    return () => {
      supabase.removeChannel(channel);
    };
  }, []);

  return {
    documents,
    loading,
    error,
    documentVersions,
    fetchDocuments,
    filterDocuments,
    createDocument,
    advanceWorkflow,
    updateDocumentWithVersioning,
    fetchDocumentVersions,
    restoreDocumentVersion,
    deleteDocument,
    deleteDocuments,
  };
}

export { };