import React from "react";

const users = [
  {
    id: 1,
    name: "Marie Dubois",
    role: "Transcripteur",
    documentsAssigned: 4,
    avatar: "MD",
    lastAccess: "Aujourd'hui",
  },
  {
    id: 2,
    name: "Thomas Martin",
    role: "Relecteur",
    documentsAssigned: 7,
    avatar: "TM",
    lastAccess: "Hier",
  },
  {
    id: 3,
    name: "Sophie Laurent",
    role: "Éditeur",
    documentsAssigned: 5,
    avatar: "SL",
    lastAccess: "Il y a 2 jours",
  },
  {
    id: 4,
    name: "Paul Morel",
    role: "Transcripteur",
    documentsAssigned: 3,
    avatar: "PM",
    lastAccess: "Il y a 1 semaine",
  },
];

const roles = [
  {
    name: "Administrateur",
    description: "Gestion du système et des utilisateurs",
    permissions: "Toutes les permissions",
    users: 1,
  },
  {
    name: "Transcripteur",
    description: "Transcription de contenus physiques",
    permissions: "Lecture, Écriture (limité)",
    users: 2,
  },
  {
    name: "Relecteur",
    description: "Vérification et correction des textes",
    permissions: "Lecture, Écriture, Validation",
    users: 1,
  },
  {
    name: "Éditeur",
    description: "Annotation et préparation à la publication",
    permissions: "Lecture, Écriture, Tags, Export",
    users: 1,
  },
];

const Users: React.FC = () => (
  <div>
    {/* Gestion des utilisateurs */}
    <div className="bg-white dark:bg-gray-800 rounded-lg shadow mb-6">
      <div className="p-6 border-b border-gray-100 dark:border-gray-700 flex justify-between items-center">
        <h2 className="text-xl font-medium text-gray-800 dark:text-white">Gestion des utilisateurs</h2>
        <button className="px-4 py-2 bg-primary hover:bg-primary-dark text-white rounded-md transition-colors">
          <i className="fas fa-user-plus mr-2"></i> Nouvel utilisateur
        </button>
      </div>
      <div className="p-6">
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
          {users.map((user) => (
            <div key={user.id} className="bg-gray-50 dark:bg-gray-700 rounded-lg p-4">
              <div className="flex items-center mb-4">
                <div className="w-12 h-12 rounded-full bg-primary text-white flex items-center justify-center text-xl font-medium">
                  {user.avatar}
                </div>
                <div className="ml-3">
                  <h3 className="font-medium text-gray-900 dark:text-white">{user.name}</h3>
                  <span className="text-sm text-gray-500 dark:text-gray-400">{user.role}</span>
                </div>
              </div>
              <div className="space-y-2 text-sm text-gray-600 dark:text-gray-400">
                <div className="flex justify-between">
                  <span>Documents assignés:</span>
                  <span className="font-medium text-gray-900 dark:text-white">{user.documentsAssigned}</span>
                </div>
                <div className="flex justify-between">
                  <span>Dernier accès:</span>
                  <span className="font-medium text-gray-900 dark:text-white">{user.lastAccess}</span>
                </div>
              </div>
              <div className="mt-4 flex gap-2">
                <button className="flex-1 py-1 text-xs bg-gray-200 hover:bg-gray-300 dark:bg-gray-600 dark:hover:bg-gray-500 text-gray-700 dark:text-gray-300 rounded transition-colors">
                  Voir
                </button>
                <button className="flex-1 py-1 text-xs bg-primary hover:bg-primary-dark text-white rounded transition-colors">
                  Modifier
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
      <div className="px-6 py-4 border-t border-gray-100 dark:border-gray-700 flex justify-between items-center">
        <span className="text-sm text-gray-500 dark:text-gray-400">{users.length} utilisateurs affichés</span>
        <div className="flex space-x-1">
          <button className="px-3 py-1 bg-gray-100 hover:bg-gray-200 dark:bg-gray-700 dark:hover:bg-gray-600 text-gray-700 dark:text-gray-300 rounded">
            <i className="fas fa-chevron-left"></i>
          </button>
          <button className="px-3 py-1 bg-primary text-white rounded">1</button>
          <button className="px-3 py-1 bg-gray-100 hover:bg-gray-200 dark:bg-gray-700 dark:hover:bg-gray-600 text-gray-700 dark:text-gray-300 rounded">
            <i className="fas fa-chevron-right"></i>
          </button>
        </div>
      </div>
    </div>

    {/* Gestion des rôles */}
    <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-6">
      <h3 className="font-medium text-gray-800 dark:text-white mb-4">Gestion des rôles</h3>
      <div className="overflow-x-auto">
        <table className="min-w-full">
          <thead className="bg-gray-50 dark:bg-gray-700">
            <tr>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider">Rôle</th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider">Description</th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider">Permissions</th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider">Utilisateurs</th>
              <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider">Actions</th>
            </tr>
          </thead>
          <tbody className="bg-white dark:bg-gray-800 divide-y divide-gray-200 dark:divide-gray-700">
            {roles.map((role) => (
              <tr key={role.name}>
                <td className="px-6 py-4 whitespace-nowrap">
                  <span className="font-medium text-gray-900 dark:text-white">{role.name}</span>
                </td>
                <td className="px-6 py-4">
                  <span className="text-sm text-gray-600 dark:text-gray-400">{role.description}</span>
                </td>
                <td className="px-6 py-4">
                  <span className="text-sm text-gray-600 dark:text-gray-400">{role.permissions}</span>
                </td>
                <td className="px-6 py-4">
                  <span className="text-sm text-gray-900 dark:text-white">{role.users}</span>
                </td>
                <td className="px-6 py-4 text-right">
                  <button className="text-primary hover:text-primary-dark">
                    <i className="fas fa-edit"></i>
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  </div>
);

export default Users;