import React, { useState, useEffect, useMemo, lazy, Suspense } from "react";
import { supabase } from '../../supabaseClient';
import { useDocuments } from "../../hooks/useDocuments";
import type { DocumentFormData, DocumentStatus } from "./document";
import { STATUS_LABELS } from "./document";
import FileUpload from './FileUpload';

// ✅ IMPORTS LAZY POUR LES MODALES
const DiffViewer = lazy(() => import('./DiffViewer'));
const StatusModal = lazy(() => import('./modals/StatusModal'));
const AssigneeModal = lazy(() => import('./modals/AssigneeModal'));
const EditModal = lazy(() => import('./modals/EditModal'));
const HistoryModal = lazy(() => import('./modals/HistoryModal'));

// ✅ INTERFACE DES PROPS
interface DocumentsProps {
  onNavigateToMediaLibrary?: () => void;
}

const Documents: React.FC<DocumentsProps> = ({ onNavigateToMediaLibrary }) => {
  const {
    documents,
    loading,
    error,
    documentVersions,
    createDocument,
    updateDocumentWithVersioning,
    fetchDocumentVersions,
    restoreDocumentVersion,
    deleteDocuments,
  } = useDocuments();

  // États
  const [searchTerm, setSearchTerm] = useState<string>("");
  const [statusFilter, setStatusFilter] = useState<string>("Tous");
  const [typeFilter, setTypeFilter] = useState<string>("Tous");
  const [isModalOpen, setIsModalOpen] = useState<boolean>(false);
  const [isHistoryModalOpen, setIsHistoryModalOpen] = useState<boolean>(false);
  const [editingDocument, setEditingDocument] = useState<any>(null);
  const [selectedDocumentForHistory, setSelectedDocumentForHistory] = useState<string | null>(null);
  const [contextMenuOpen, setContextMenuOpen] = useState<string | null>(null);
  const [diffViewerOpen, setDiffViewerOpen] = useState(false);
  const [versionsToCompare, setVersionsToCompare] = useState<{ old: any; new: any } | null>(null);
  const [newDocument, setNewDocument] = useState<DocumentFormData>({
    title: "",
    type: "Transcription",
    source: "",
    status: "imported",
    progress: 0,
    assigned_to: "",
    tags: [],
    file_url: "",
  });
  const [formErrors, setFormErrors] = useState({
    title: false,
    source: false,
    assigned_to: false,
  });
  const [tagsInput, setTagsInput] = useState<string>("");
  const [selectedDocuments, setSelectedDocuments] = useState<string[]>([]);
  
  // États pour les modales Bulk Actions
  const [statusModalOpen, setStatusModalOpen] = useState(false);
  const [assigneeModalOpen, setAssigneeModalOpen] = useState(false);
  const [selectedStatus, setSelectedStatus] = useState<DocumentStatus | null>(null);
  const [selectedAssignee, setSelectedAssignee] = useState<string | null>(null);

  // 🔑 PAGINATION (6 docs/page)
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 6;

  // Options métier
  const documentTypes = ["Transcription", "Audio", "Édition", "Vidéo", "Image"];
  
  // ✅ NOUVEAUX STATUTS (Workflow mis à jour)
  const documentStatuses: DocumentStatus[] = [
    'imported',
    'transcribing',
    'transcribed',
    'book_project',
    'proofreading_1',
    'proofreading_2',
    'edited'
  ];
  
  const assignees = ["Non assigné", "Marie Dubois", "Thomas Martin", "Sophie Laurent", "Paul Morel", "Jean Dupont"];

  // Fermer menu au clic extérieur
  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      const target = e.target as HTMLElement;
      if (!target.closest('.context-menu-button') && !target.closest('.context-menu')) {
        setContextMenuOpen(null);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Filtrage optimisé
  const filteredDocuments = useMemo(() => {
    return documents.filter((doc: any) => {
      const searchLower = searchTerm.toLowerCase().trim();
      const matchesSearch = searchLower === "" ||
        doc.title.toLowerCase().includes(searchLower) ||
        doc.tags.some((tag: string) => tag.toLowerCase().includes(searchLower));
      const matchesStatus = statusFilter === "Tous" || doc.status === statusFilter;
      const matchesType = typeFilter === "Tous" || doc.type === typeFilter;
      return matchesSearch && matchesStatus && matchesType;
    });
  }, [documents, searchTerm, statusFilter, typeFilter]);

  // 🔑 PAGINATION (6 docs/page)
  const paginatedDocuments = useMemo(() => {
    const startIndex = (currentPage - 1) * itemsPerPage;
    return filteredDocuments.slice(startIndex, startIndex + itemsPerPage);
  }, [filteredDocuments, currentPage, itemsPerPage]);

  const totalPages = Math.ceil(filteredDocuments.length / itemsPerPage);

  // Réinitialiser la page 1 quand les filtres changent
  useEffect(() => {
    setCurrentPage(1);
  }, [searchTerm, statusFilter, typeFilter]);

  const uniqueTypes = useMemo(() => {
    const types = ["Tous", ...new Set(documents.map((doc: any) => doc.type))];
    return types;
  }, [documents]);

  // Gestion de la sélection multiple
  const toggleDocumentSelection = (documentId: string) => {
    setSelectedDocuments(prev =>
      prev.includes(documentId)
        ? prev.filter(id => id !== documentId)
        : [...prev, documentId]
    );
  };

  const toggleSelectAll = () => {
    if (selectedDocuments.length === paginatedDocuments.length && paginatedDocuments.length > 0) {
      setSelectedDocuments([]);
    } else {
      setSelectedDocuments(paginatedDocuments.map((doc: any) => doc.id));
    }
  };

  // Suppression multiple
  const handleDeleteSelected = async () => {
    if (selectedDocuments.length === 0) return;
    const confirmation = window.confirm(
      `Êtes-vous sûr de vouloir supprimer ${selectedDocuments.length} document${selectedDocuments.length > 1 ? 's' : ''} ?\nCette action est irréversible.`
    );
    if (confirmation) {
      try {
        await deleteDocuments(selectedDocuments);
        alert(`✅ ${selectedDocuments.length} document${selectedDocuments.length > 1 ? 's' : ''} supprimé${selectedDocuments.length > 1 ? 's' : ''} avec succès !`);
        setSelectedDocuments([]);
        if (currentPage > 1 && paginatedDocuments.length === 1) {
          setCurrentPage(prev => prev - 1);
        }
      } catch (err) {
        console.error('Erreur suppression:', err);
        alert('❌ Erreur suppression');
      }
    }
  };

  // Bulk actions - Changer statut
  const handleBulkStatusChange = async (newStatus: DocumentStatus) => {
    if (!selectedStatus) {
      alert('⚠️ Veuillez sélectionner un statut');
      return;
    }
    if (selectedDocuments.length === 0 || !newStatus) {
      alert('⚠️ Aucun document sélectionné');
      return;
    }
    const confirmation = window.confirm(
      `Changer le statut de ${selectedDocuments.length} document${selectedDocuments.length > 1 ? 's' : ''} en "${STATUS_LABELS[newStatus]}" ?`
    );
    if (!confirmation) return;
    try {
      const results = await Promise.all(
        selectedDocuments.map(async (id) => {
          const doc = documents.find(d => d.id === id);
          if (!doc) return null;
          return await updateDocumentWithVersioning(id, { 
            ...doc, 
            status: newStatus,
            workflow_step: getWorkflowStep(newStatus),
            progress: getWorkflowProgress(newStatus)
          });
        })
      );
      const successCount = results.filter(r => r !== null).length;
      alert(`✅ ${successCount} document${successCount > 1 ? 's' : ''} mis à jour avec le statut "${STATUS_LABELS[newStatus]}" !`);
      setSelectedDocuments([]);
      setStatusModalOpen(false);
      setSelectedStatus(null);
    } catch (err) {
      console.error('❌ Erreur changement statut:', err);
      alert('❌ Erreur lors du changement de statut');
    }
  };

  // Bulk actions - Réassigner
  const handleBulkReassign = async (newAssignee: string) => {
    if (!selectedAssignee) {
      alert('⚠️ Veuillez sélectionner un assigné');
      return;
    }
    if (selectedDocuments.length === 0 || !newAssignee) {
      alert('⚠️ Aucun document sélectionné');
      return;
    }
    const confirmation = window.confirm(
      `Réassigner ${selectedDocuments.length} document${selectedDocuments.length > 1 ? 's' : ''} à "${newAssignee}" ?`
    );
    if (!confirmation) return;
    try {
      const results = await Promise.all(
        selectedDocuments.map(async (id) => {
          const doc = documents.find(d => d.id === id);
          if (!doc) return null;
          return await updateDocumentWithVersioning(id, { ...doc, assigned_to: newAssignee });
        })
      );
      const successCount = results.filter(r => r !== null).length;
      alert(`✅ ${successCount} document${successCount > 1 ? 's' : ''} réassigné${successCount > 1 ? 's' : ''} à ${newAssignee} !`);
      setSelectedDocuments([]);
      setAssigneeModalOpen(false);
      setSelectedAssignee(null);
    } catch (err) {
      console.error('❌ Erreur réassignation:', err);
      alert('❌ Erreur lors de la réassignation');
    }
  };

  // Gestion de l'édition
  const handleEditDocument = (doc: any) => {
    setEditingDocument(doc);
    setNewDocument({
      title: doc.title,
      type: doc.type,
      source: doc.source,
      status: doc.status,
      progress: doc.progress,
      assigned_to: doc.assigned_to,
      tags: doc.tags || [],
      file_url: doc.file_url || '',
    });
    setTagsInput('');
    setIsModalOpen(true);
  };

  // Gestion des tags
  const handleAddTag = () => {
    const tag = tagsInput.trim();
    if (tag && !newDocument.tags?.includes(tag)) {
      setNewDocument(prev => ({
        ...prev,
        tags: [...(prev.tags || []), tag]
      }));
      setTagsInput('');
    }
  };

  const handleRemoveTag = (tagToRemove: string) => {
    setNewDocument(prev => ({
      ...prev,
      tags: (prev.tags || []).filter(tag => tag !== tagToRemove)
    }));
  };

  // Validation du formulaire
  const validateForm = () => {
    const newErrors = {
      title: newDocument.title.trim() === "",
      source: newDocument.source.trim() === "",
      assigned_to: newDocument.assigned_to === "",
    };
    setFormErrors(newErrors);
    return !newErrors.title && !newErrors.source && !newErrors.assigned_to;
  };

  // Soumission du formulaire
  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validateForm()) return;
    try {
      if (editingDocument) {
        await updateDocumentWithVersioning(editingDocument.id, newDocument);
        alert("✅ Document mis à jour avec succès !\nUne nouvelle version a été sauvegardée.");
      } else {
        await createDocument(newDocument);
        alert("✅ Document créé avec succès !");
      }
      setEditingDocument(null);
      setIsModalOpen(false);
      setNewDocument({
        title: "",
        type: "Transcription",
        source: "",
        status: "imported",
        progress: 0,
        assigned_to: "",
        tags: [],
        file_url: ""
      });
      setFormErrors({ title: false, source: false, assigned_to: false });
      setTagsInput('');
    } catch (err: any) {
      console.error(editingDocument ? 'Erreur mise à jour:' : 'Erreur création:', err);
      const errorMessage = err instanceof Error ? err.message : String(err);
      if (errorMessage.includes('Non authentifié')) {
        await supabase.auth.signOut();
        alert("🔒 Session invalide. Redirection...");
        window.location.href = "/login";
        return;
      }
      alert(editingDocument
        ? `❌ Erreur mise à jour:\n${errorMessage}`
        : `❌ Erreur création:\n${errorMessage}`
      );
    }
  };

  // Menu contextuel
  const toggleContextMenu = (documentId: string) => {
    setContextMenuOpen(prev => prev === documentId ? null : documentId);
  };

  const handleExportPDF = (doc: any) => {
    setContextMenuOpen(null);
    alert(`📄 Export PDF pour "${doc.title}"\n(Utilisez Ctrl+P pour imprimer en PDF)`);
  };

  const handleShareDocument = (doc: any) => {
    setContextMenuOpen(null);
    const shareUrl = `${window.location.origin}/documents/${doc.id}`;
    navigator.clipboard.writeText(shareUrl).then(() => {
      alert(`🔗 Lien copié :\n${shareUrl}`);
    });
  };

  const handleDuplicateDocument = async (doc: any) => {
    setContextMenuOpen(null);
    if (window.confirm(`Dupliquer "${doc.title}" ?`)) {
      try {
        await createDocument({
          title: `${doc.title} (copie)`,
          type: doc.type,
          source: doc.source,
          status: "imported",
          progress: 0,
          assigned_to: doc.assigned_to,
          tags: [...(doc.tags || [])],
          file_url: doc.file_url || ''
        });
        alert("✅ Document dupliqué !");
      } catch (err) {
        alert("❌ Erreur duplication");
      }
    }
  };

  const handleShowStats = (doc: any) => {
    setContextMenuOpen(null);
    const days = Math.floor((new Date().getTime() - new Date(doc.created_at).getTime()) / (1000 * 60 * 60 * 24));
    alert(`📊 "${doc.title}"\n• Créé il y a ${days} jour${days > 1 ? 's' : ''}\n• ${doc.tags?.length || 0} tags\n• Statut: ${STATUS_LABELS[doc.status as DocumentStatus]}`);
  };

  const handleOpenHistory = async (documentId: string) => {
    setContextMenuOpen(null);
    setSelectedDocumentForHistory(documentId);
    await fetchDocumentVersions(documentId);
    setIsHistoryModalOpen(true);
  };

  const handleRestoreVersion = async (versionId: string) => {
    const reason = prompt("Raison de la restauration (optionnel) :");
    if (selectedDocumentForHistory) {
      try {
        await restoreDocumentVersion(selectedDocumentForHistory, versionId, reason || 'Restauration manuelle');
        alert("✅ Version restaurée !");
        setIsHistoryModalOpen(false);
      } catch (err) {
        alert("❌ Erreur restauration");
      }
    }
  };

  // Comparaison de versions
  const handleCompareVersions = (newVersion: any) => {
    const currentIndex = documentVersions.findIndex((v: any) => v.id === newVersion.id);
    if (currentIndex < documentVersions.length - 1) {
      const oldVersion = documentVersions[currentIndex + 1];
      setVersionsToCompare({ old: oldVersion, new: newVersion });
      setDiffViewerOpen(true);
    } else {
      alert("ℹ️ Cette version est la plus ancienne disponible.\nImpossible de comparer avec une version précédente.");
    }
  };

  // Fonctions utilitaires
  const closeModal = () => {
    setIsModalOpen(false);
    setEditingDocument(null);
    setNewDocument({
      title: "",
      type: "Transcription",
      source: "",
      status: "imported",
      progress: 0,
      assigned_to: "",
      tags: [],
      file_url: ""
    });
    setFormErrors({ title: false, source: false, assigned_to: false });
    setTagsInput('');
    setContextMenuOpen(null);
  };

  const closeHistoryModal = () => {
    setIsHistoryModalOpen(false);
    setSelectedDocumentForHistory(null);
  };

  const formatDate = (dateString: string): string => {
    try {
      return new Intl.DateTimeFormat('fr-FR', { year: 'numeric', month: 'long', day: 'numeric' }).format(new Date(dateString));
    } catch { return dateString; }
  };

  const formatDateTime = (dateString: string): string => {
    try {
      return new Intl.DateTimeFormat('fr-FR', { year: 'numeric', month: 'long', day: 'numeric', hour: '2-digit', minute: '2-digit' }).format(new Date(dateString));
    } catch { return dateString; }
  };

  // 🔑 COMPOSANT DE CHARGEMENT POUR LES MODALES
  const ModalLoader = () => (
    <div className="fixed inset-0 flex items-center justify-center z-50">
      <div className="bg-white dark:bg-gray-800 rounded-xl shadow-2xl p-8">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary mx-auto"></div>
        <p className="text-gray-600 dark:text-gray-400 mt-4 text-center">Chargement...</p>
      </div>
    </div>
  );

  // ✅ NOUVELLE GESTION DES COULEURS DE STATUT
  const statusClass = (status: string) => {
    switch (status) {
      case "edited": return "text-purple-800 bg-purple-100 dark:bg-purple-900 dark:text-purple-200";
      case "proofreading_2": return "text-red-800 bg-red-100 dark:bg-red-900 dark:text-red-200";
      case "proofreading_1": return "text-amber-800 bg-amber-100 dark:bg-amber-900 dark:text-amber-200";
      case "book_project": return "text-indigo-800 bg-indigo-100 dark:bg-indigo-900 dark:text-indigo-200";
      case "transcribed": return "text-emerald-800 bg-emerald-100 dark:bg-emerald-900 dark:text-emerald-200";
      case "transcribing": return "text-cyan-800 bg-cyan-100 dark:bg-cyan-900 dark:text-cyan-200";
      case "imported": return "text-gray-800 bg-gray-100 dark:bg-gray-700 dark:text-gray-200";
      default: return "text-gray-500 bg-gray-100 dark:bg-gray-700";
    }
  };

  // ✅ NOUVEAU WORKFLOW (5 étapes)
  const getWorkflowStep = (status: DocumentStatus): 1 | 2 | 3 | 4 | 5 => {
    const steps: Record<DocumentStatus, 1 | 2 | 3 | 4 | 5> = {
      'imported': 1,
      'transcribing': 2,
      'transcribed': 2,
      'book_project': 3,
      'proofreading_1': 4,
      'proofreading_2': 5,
      'edited': 5
    };
    return steps[status];
  };

  // ✅ NOUVELLE PROGRESSION
  const getWorkflowProgress = (status: DocumentStatus): number => {
    switch (status) {
      case 'imported': return 0;
      case 'transcribing': return 20;
      case 'transcribed': return 40;
      case 'book_project': return 60;
      case 'proofreading_1': return 80;
      case 'proofreading_2': return 100;
      case 'edited': return 100;
      default: return 0;
    }
  };

  // 🔑 SKELETON DE CHARGEMENT
  const SkeletonCard = () => (
    <div className="bg-white dark:bg-gray-800 rounded-xl shadow-sm border border-gray-100 dark:border-gray-700 p-5 pt-8 animate-pulse">
      <div className="absolute top-3 right-3">
        <div className="w-6 h-6 bg-gray-200 dark:bg-gray-700 rounded-full"></div>
      </div>
      <div className="flex justify-between items-start mb-4">
        <div className="h-6 bg-gray-200 dark:bg-gray-700 rounded w-3/4"></div>
        <div className="h-6 bg-gray-200 dark:bg-gray-700 rounded w-20"></div>
      </div>
      <div className="space-y-2 mb-4">
        <div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-1/2"></div>
        <div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-2/3"></div>
      </div>
      <div className="mb-4">
        <div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-full mb-2"></div>
        <div className="h-2 bg-gray-200 dark:bg-gray-700 rounded w-full"></div>
      </div>
      <div className="mb-4">
        <div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-1/3 mb-2"></div>
        <div className="h-2 bg-gray-200 dark:bg-gray-700 rounded w-full"></div>
      </div>
      <div className="flex justify-between items-center mb-4 pt-3 border-t border-gray-100 dark:border-gray-700">
        <div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-1/2"></div>
        <div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-1/4"></div>
      </div>
      <div className="flex gap-2 mb-4 pt-3 border-t border-gray-100 dark:border-gray-700">
        <div className="h-5 bg-gray-200 dark:bg-gray-700 rounded w-16"></div>
        <div className="h-5 bg-gray-200 dark:bg-gray-700 rounded w-16"></div>
        <div className="h-5 bg-gray-200 dark:bg-gray-700 rounded w-16"></div>
      </div>
      <div className="flex gap-2 pt-4 border-t border-gray-100 dark:border-gray-700">
        <div className="h-9 bg-gray-200 dark:bg-gray-700 rounded w-full"></div>
        <div className="h-9 bg-gray-200 dark:bg-gray-700 rounded w-1/3"></div>
      </div>
    </div>
  );

  // Rendu JSX
  return (
    <div className="container mx-auto px-4 py-4 h-full flex flex-col">
      {/* Barre d'outils */}
      <div className="bg-white dark:bg-gray-800 rounded-lg shadow mb-4 p-4 z-10 transition-all duration-300">
        <div className="flex flex-col md:flex-row gap-4">
          <div className="flex-1">
            <div className="relative">
              <input
                id="search-documents"
                type="text"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-10 pr-4 py-2 text-base border border-gray-300 dark:border-gray-700 rounded-md focus:outline-none focus:ring-2 focus:ring-primary focus:border-transparent dark:bg-gray-700 dark:text-white transition-all duration-200"
                placeholder="Rechercher un document..."
              />
              <i className="fas fa-search absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400"></i>
            </div>
          </div>
          <div className="flex gap-3 flex-wrap md:flex-nowrap">
            <div className="w-full md:w-auto">
              <select
                value={statusFilter}
                onChange={(e) => setStatusFilter(e.target.value)}
                className="w-full md:w-auto py-2 px-3 text-base border border-gray-300 dark:border-gray-700 rounded-md focus:outline-none focus:ring-2 focus:ring-primary focus:border-transparent dark:bg-gray-700 dark:text-white transition-all duration-200"
              >
                <option value="Tous">Tous les statuts</option>
                {documentStatuses.map((status) => (
                  <option key={status} value={status}>
                    {STATUS_LABELS[status]}
                  </option>
                ))}
              </select>
            </div>
            <div className="w-full md:w-auto">
              <select
                value={typeFilter}
                onChange={(e) => setTypeFilter(e.target.value)}
                className="w-full md:w-auto py-2 px-3 text-base border border-gray-300 dark:border-gray-700 rounded-md focus:outline-none focus:ring-2 focus:ring-primary focus:border-transparent dark:bg-gray-700 dark:text-white transition-all duration-200"
              >
                {uniqueTypes.map((type: any) => (
                  <option key={type} value={type}>
                    {type === "Tous" ? "Tous les types" : type}
                  </option>
                ))}
              </select>
            </div>
            
            {/* ✅ BOUTON NOUVEAU DOCUMENT */}
            <button
              onClick={() => { setEditingDocument(null); setIsModalOpen(true); }}
              className="flex-none px-4 py-2 bg-primary hover:bg-primary-dark text-white rounded-md transition-all duration-200 flex items-center hover:shadow-lg transform hover:-translate-y-0.5"
            >
              <i className="fas fa-plus mr-2"></i> Nouveau document
            </button>
            
            {/* ✅ BOUTON MÉDIATHÈQUE */}
            {onNavigateToMediaLibrary && (
              <button
                onClick={onNavigateToMediaLibrary}
                className="flex-none px-4 py-2 bg-purple-600 hover:bg-purple-700 text-white rounded-md transition-all duration-200 flex items-center hover:shadow-lg transform hover:-translate-y-0.5"
              >
                <i className="fas fa-folder-open mr-2"></i> Médiathèque
              </button>
            )}
          </div>
        </div>
      </div>

      {/* Statistiques et sélection */}
      <div className="mb-4 flex flex-col sm:flex-row sm:justify-between sm:items-center gap-3 transition-all duration-300">
        <p className="text-sm text-gray-600 dark:text-gray-400">
          <strong>{paginatedDocuments.length}</strong> document{paginatedDocuments.length > 1 ? 's' : ''} affiché{paginatedDocuments.length > 1 ? 's' : ''} sur <strong>{filteredDocuments.length}</strong> filtré{filteredDocuments.length > 1 ? 's' : ''} (total: <strong>{documents.length}</strong>)
        </p>
        {paginatedDocuments.length > 0 && (
          <div className="flex items-center gap-2">
            <label className="flex items-center text-sm text-gray-600 dark:text-gray-400 cursor-pointer transition-colors">
              <input
                type="checkbox"
                checked={paginatedDocuments.length > 0 && selectedDocuments.length === paginatedDocuments.length}
                onChange={toggleSelectAll}
                className="w-4 h-4 text-primary border-gray-300 rounded focus:ring-primary dark:bg-gray-700 dark:border-gray-600 transition-colors"
              />
              <span className="ml-2">Sélectionner tout</span>
            </label>
            {selectedDocuments.length > 0 && (
              <span className="text-xs font-medium text-primary bg-primary/10 dark:bg-primary/20 px-2.5 py-1 rounded-full animate-fade-in">
                {selectedDocuments.length} sélectionné{selectedDocuments.length > 1 ? 's' : ''}
              </span>
            )}
          </div>
        )}
      </div>

      {/* Message d'erreur */}
      {error && (
        <div className="mb-4 p-4 bg-red-50 dark:bg-red-900/20 text-red-700 dark:text-red-300 rounded-lg animate-slide-down">
          <i className="fas fa-exclamation-triangle mr-2"></i>
          {error}
        </div>
      )}

      {/* Cadre documents */}
      <div className="bg-white dark:bg-gray-800 rounded-lg shadow flex-1 overflow-visible border border-gray-200 dark:border-gray-700 transition-all duration-300">
        {/* EN-TÊTE AVEC BOUTONS BULK ACTIONS */}
        <div className="bg-gray-50 dark:bg-gray-700/50 px-6 py-4 border-b border-gray-200 dark:border-gray-700 flex flex-col sm:flex-row sm:justify-between sm:items-center gap-3">
          <h2 className="font-semibold text-gray-800 dark:text-gray-200 text-lg flex items-center">
            <i className="fas fa-book-open mr-2 text-primary"></i>
            Bibliothèque éditoriale
          </h2>
          
          {/* BOUTONS BULK ACTIONS */}
          {selectedDocuments.length > 0 && (
            <div className="flex flex-wrap gap-2" data-bulk-modal>
              <button
                onClick={() => {
                  console.log('🖱️ [DEBUG] Ouverture modale statut');
                  console.log('📋 Documents sélectionnés:', selectedDocuments);
                  setStatusModalOpen(true);
                }}
                className="px-3 py-1.5 bg-green-600 hover:bg-green-700 text-white rounded-md text-xs flex items-center gap-1.5 transition-all duration-200 hover:shadow-lg transform hover:-translate-y-0.5"
              >
                <i className="fas fa-exchange-alt"></i>
                Changer statut
              </button>
              
              <button
                onClick={() => {
                  console.log('🖱️ [DEBUG] Ouverture modale réassigner');
                  console.log('📋 Documents sélectionnés:', selectedDocuments);
                  setAssigneeModalOpen(true);
                }}
                className="px-3 py-1.5 bg-purple-600 hover:bg-purple-700 text-white rounded-md text-xs flex items-center gap-1.5 transition-all duration-200 hover:shadow-lg transform hover:-translate-y-0.5"
              >
                <i className="fas fa-user-edit"></i>
                Réassigner
              </button>
              
              <button
                onClick={handleDeleteSelected}
                className="px-3 py-1.5 bg-red-600 hover:bg-red-700 text-white rounded-md text-xs flex items-center gap-1.5 transition-all duration-200 hover:shadow-lg transform hover:-translate-y-0.5"
              >
                <i className="fas fa-trash-alt"></i>
                Supprimer ({selectedDocuments.length})
              </button>
            </div>
          )}
        </div>
        
        <div className="overflow-y-auto h-full" style={{ maxHeight: 'calc(100vh - 280px)' }}>
          {loading ? (
            /* 🔑 SKELETONS DE CHARGEMENT (6 cartes) */
            <div className="p-6">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {[...Array(6)].map((_, i) => (
                  <SkeletonCard key={i} />
                ))}
              </div>
            </div>
          ) : (
            <div className="p-6">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {paginatedDocuments.length === 0 ? (
                  <div className="col-span-full py-16 text-center animate-fade-in">
                    <div className="inline-block p-4 bg-gray-100 dark:bg-gray-700 rounded-full mb-4">
                      <i className="fas fa-search text-4xl text-gray-400"></i>
                    </div>
                    <p className="text-lg text-gray-600 dark:text-gray-300 font-medium mb-2">
                      Aucun document trouvé
                    </p>
                    {searchTerm && (
                      <button
                        onClick={() => setSearchTerm('')}
                        className="mt-4 px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-md text-sm transition-all duration-200"
                      >
                        Effacer la recherche
                      </button>
                    )}
                  </div>
                ) : (
                  paginatedDocuments.map((doc: any, index: number) => (
                    <article
                      key={doc.id}
                      className={`relative bg-white dark:bg-gray-800 rounded-xl shadow-sm hover:shadow-md transition-all duration-300 border ${
                        selectedDocuments.includes(doc.id)
                          ? 'border-red-400 dark:border-red-500 ring-2 ring-red-200 dark:ring-red-900/50'
                          : 'border-gray-100 dark:border-gray-700'
                      } overflow-visible transform hover:-translate-y-1 animate-fade-in`}
                      role="listitem"
                      style={{ animationDelay: `${index * 50}ms` }}
                    >
                      {/* Checkbox de sélection */}
                      <div
                        className="absolute top-3 right-3 z-10"
                        onClick={(e) => { e.stopPropagation(); toggleDocumentSelection(doc.id); }}
                      >
                        <div className={`flex items-center justify-center w-6 h-6 rounded-full cursor-pointer transition-all duration-200 ${
                          selectedDocuments.includes(doc.id)
                            ? 'bg-red-100 border-2 border-red-500 dark:bg-red-900/40 dark:border-red-500'
                            : 'bg-white/90 dark:bg-gray-800 border border-gray-300 dark:border-gray-600 hover:border-red-400'
                        }`}>
                          {selectedDocuments.includes(doc.id) && (
                            <i className="fas fa-check text-red-500 dark:text-red-400 text-xs font-bold animate-scale-in"></i>
                          )}
                        </div>
                      </div>
                      <div className="p-5 pt-8">
                        {/* Titre et statut */}
                        <div className="flex flex-col sm:flex-row sm:justify-between sm:items-start mb-4">
                          <h3 className="font-bold text-gray-900 dark:text-white text-lg mb-1 sm:mb-0 line-clamp-2 transition-colors">
                            {doc.title}
                          </h3>
                          <span className={`px-3 py-1 text-sm font-medium rounded-full ${statusClass(doc.status)} whitespace-nowrap transition-all duration-200`}>
                            {STATUS_LABELS[doc.status as DocumentStatus]}
                          </span>
                        </div>
                        
                        {/* Type et source */}
                        <div className="text-sm text-gray-600 dark:text-gray-400 mb-4">
                          <div className="flex flex-wrap gap-3">
                            <span className="flex items-center transition-colors"><i className="fas fa-file-alt mr-1.5 text-gray-400 text-xs"></i> {doc.type}</span>
                            <span className="flex items-center transition-colors"><i className="fas fa-bookmark mr-1.5 text-gray-400 text-xs"></i> {doc.source}</span>
                          </div>
                        </div>
                        
                        {/* Workflow visuel */}
                        <div className="mb-4">
                          <div className="flex items-center justify-between text-xs text-gray-500 dark:text-gray-400 mb-1.5">
                            <span className="flex items-center">
                              <i className="fas fa-sync-alt mr-1.5 text-blue-500"></i>
                              Étape {getWorkflowStep(doc.status as DocumentStatus)} / 5
                            </span>
                            <span>{getWorkflowProgress(doc.status as DocumentStatus)}%</span>
                          </div>
                          <div className="w-full bg-gray-200 dark:bg-gray-700 rounded-full h-2 overflow-hidden">
                            <div
                              className="h-full bg-gradient-to-r from-blue-500 to-indigo-600 transition-all duration-500 ease-out"
                              style={{ width: `${getWorkflowProgress(doc.status as DocumentStatus)}%` }}
                            ></div>
                          </div>
                        </div>
                        
                        {/* Progression */}
                        <div className="mb-4">
                          <div className="flex justify-between items-center mb-1.5">
                            <span className="text-xs text-gray-500 dark:text-gray-400 font-medium">Progression</span>
                            <span className="text-xs font-medium text-gray-700 dark:text-gray-300">{doc.progress}%</span>
                          </div>
                          <div className="w-full bg-gray-100 dark:bg-gray-700 rounded-full h-2 overflow-hidden">
                            <div
                              className="bg-primary rounded-full h-2 transition-all duration-300 ease-in-out"
                              style={{ width: `${doc.progress}%` }}
                            ></div>
                          </div>
                        </div>
                        
                        {/* Assignation et date */}
                        <div className="flex flex-col sm:flex-row sm:justify-between sm:items-center mb-4 pt-3 border-t border-gray-100 dark:border-gray-700">
                          <div className="flex items-center mb-2 sm:mb-0">
                            <i className="fas fa-user mr-2 text-gray-400 text-xs"></i>
                            <span className="font-medium text-gray-700 dark:text-gray-300 text-sm">{doc.assigned_to}</span>
                          </div>
                          <time className="text-xs text-gray-500 dark:text-gray-400" dateTime={doc.updated_at}>
                            <i className="fas fa-clock mr-1 text-gray-400 text-xs"></i>
                            {formatDate(doc.updated_at)}
                          </time>
                        </div>
                        
                        {/* Tags */}
                        <div className="mt-3 pt-3 border-t border-gray-100 dark:border-gray-700">
                          <div className="flex flex-wrap gap-1.5">
                            {doc.tags.map((tag: string, index: number) => (
                              <span key={`${doc.id}-tag-${index}`} className="px-2 py-0.5 text-xs bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-300 rounded-md transition-all duration-200 hover:bg-gray-200 dark:hover:bg-gray-600">
                                #{tag}
                              </span>
                            ))}
                            {doc.tags.length === 0 && <span className="text-xs text-gray-400 italic">Aucun tag</span>}
                          </div>
                        </div>
                        
                        {/* Mini-timeline */}
                        <div className="mt-4 pt-3 border-t border-gray-100 dark:border-gray-700">
                          <div className="flex items-center text-xs text-gray-500 dark:text-gray-400 mb-2">
                            <i className="fas fa-history mr-1.5 text-amber-500"></i>
                            <span>Dernières modifications</span>
                          </div>
                          <div className="relative pl-3.5">
                            <div className="relative mb-2">
                              <div className="absolute left-0 top-1.5 w-2.5 h-2.5 bg-green-500 rounded-full border-2 border-white dark:border-gray-800 animate-pulse"></div>
                              <div className="ml-4 bg-green-50 dark:bg-green-900/20 text-green-800 dark:text-green-200 px-2 py-1 rounded text-xs">
                                Version actuelle
                              </div>
                            </div>
                          </div>
                        </div>
                        
                        {/* Boutons */}
                        <div className="mt-5 pt-4 border-t border-gray-100 dark:border-gray-700 flex flex-col sm:flex-row gap-2">
                          <button
                            onClick={() => handleEditDocument(doc)}
                            className="flex-1 px-3.5 py-2 text-sm bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-medium transition-all duration-200 flex items-center justify-center hover:shadow-lg transform hover:-translate-y-0.5"
                            aria-label={`Modifier ${doc.title}`}
                          >
                            <i className="fas fa-pen mr-1.5"></i> Modifier
                          </button>
                          
                          {/* MENU CONTEXTUEL - z-30 + z-[100] + bottom-full */}
                          <div className="relative z-30">
                            <button
                              onClick={(e) => { e.stopPropagation(); toggleContextMenu(doc.id); }}
                              className="context-menu-button px-3.5 py-2 text-sm bg-gray-100 hover:bg-gray-200 dark:bg-gray-700 dark:hover:bg-gray-600 text-gray-700 dark:text-gray-300 rounded-lg font-medium transition-colors flex items-center justify-center w-full sm:w-auto"
                              aria-label={`Options pour ${doc.title}`}
                              aria-expanded={contextMenuOpen === doc.id}
                            >
                              <i className="fas fa-ellipsis-v"></i>
                            </button>
                            
                            {contextMenuOpen === doc.id && (
                              <div
                                className="context-menu absolute right-0 bottom-full mb-2 w-56 bg-white dark:bg-gray-800 rounded-lg shadow-2xl z-[100] border border-gray-200 dark:border-gray-700 py-1"
                                role="menu"
                                onClick={(e) => e.stopPropagation()}
                              >
                                <button onClick={() => handleExportPDF(doc)} className="w-full flex items-center px-3.5 py-2 text-sm hover:bg-gray-100 dark:hover:bg-gray-700/50 transition-colors">
                                  <i className="fas fa-file-pdf mr-2.5 text-red-500"></i> Exporter en PDF
                                </button>
                                <button onClick={() => handleShareDocument(doc)} className="w-full flex items-center px-3.5 py-2 text-sm hover:bg-gray-100 dark:hover:bg-gray-700/50 transition-colors">
                                  <i className="fas fa-share-alt mr-2.5 text-blue-500"></i> Partager
                                </button>
                                <button onClick={() => handleDuplicateDocument(doc)} className="w-full flex items-center px-3.5 py-2 text-sm hover:bg-gray-100 dark:hover:bg-gray-700/50 transition-colors">
                                  <i className="fas fa-copy mr-2.5 text-green-500"></i> Dupliquer
                                </button>
                                <button onClick={() => handleShowStats(doc)} className="w-full flex items-center px-3.5 py-2 text-sm hover:bg-gray-100 dark:hover:bg-gray-700/50 transition-colors">
                                  <i className="fas fa-chart-line mr-2.5 text-purple-500"></i> Statistiques
                                </button>
                                <div className="h-px bg-gray-200 dark:bg-gray-700 my-1"></div>
                                <button onClick={() => handleOpenHistory(doc.id)} className="w-full flex items-center px-3.5 py-2 text-sm text-amber-700 dark:text-amber-400 hover:bg-amber-50 dark:hover:bg-amber-900/20 transition-colors">
                                  <i className="fas fa-history mr-2.5 text-amber-500"></i> Historique complet
                                </button>
                              </div>
                            )}
                          </div>
                        </div>
                      </div>
                    </article>
                  ))
                )}
              </div>
            </div>
          )}
        </div>
      </div>

      {/* 🔑 PAGINATION (6 docs/page) */}
      {totalPages > 1 && (
        <div className="mt-6 flex flex-col sm:flex-row sm:justify-between sm:items-center gap-4 animate-fade-in">
          <p className="text-sm text-gray-600 dark:text-gray-400">
            Page {currentPage} sur {totalPages} • {filteredDocuments.length} résultat{filteredDocuments.length > 1 ? 's' : ''} filtré{filteredDocuments.length > 1 ? 's' : ''}
          </p>
          
          <div className="flex items-center gap-2">
            <button
              onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
              disabled={currentPage === 1}
              className="px-3 py-1.5 border border-gray-300 dark:border-gray-600 rounded-lg disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-100 dark:hover:bg-gray-700 transition-all duration-200"
            >
              <i className="fas fa-chevron-left"></i>
            </button>
            
            {[...Array(Math.min(5, totalPages))].map((_, i) => {
              const pageNum = Math.max(1, currentPage - 2) + i;
              if (pageNum > totalPages) return null;
              return (
                <button
                  key={pageNum}
                  onClick={() => setCurrentPage(pageNum)}
                  className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-all duration-200 ${
                    currentPage === pageNum
                      ? 'bg-primary text-white shadow-lg'
                      : 'bg-white dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-600'
                  }`}
                >
                  {pageNum}
                </button>
              );
            })}
            
            {totalPages > 5 && currentPage < totalPages - 1 && (
              <span className="px-3 py-1.5 text-sm text-gray-500 dark:text-gray-400">...</span>
            )}
            
            {totalPages > 5 && (
              <button
                onClick={() => setCurrentPage(totalPages)}
                className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-all duration-200 ${
                  currentPage === totalPages
                    ? 'bg-primary text-white shadow-lg'
                    : 'bg-white dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-600'
                }`}
              >
                {totalPages}
              </button>
            )}
            
            <button
              onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
              disabled={currentPage === totalPages}
              className="px-3 py-1.5 border border-gray-300 dark:border-gray-600 rounded-lg disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-100 dark:hover:bg-gray-700 transition-all duration-200"
            >
              <i className="fas fa-chevron-right"></i>
            </button>
          </div>
        </div>
      )}

      {/* ✅ MODALES AVEC LAZY LOADING */}
      <Suspense fallback={<ModalLoader />}>
        {statusModalOpen && (
          <StatusModal
            isOpen={statusModalOpen}
            onClose={() => {
              setStatusModalOpen(false);
              setSelectedStatus(null);
            }}
            selectedDocuments={selectedDocuments}
            selectedStatus={selectedStatus}
            setSelectedStatus={setSelectedStatus}
            onValidate={handleBulkStatusChange}
            documentStatuses={documentStatuses}
            statusClass={statusClass}
          />
        )}

        {assigneeModalOpen && (
          <AssigneeModal
            isOpen={assigneeModalOpen}
            onClose={() => {
              setAssigneeModalOpen(false);
              setSelectedAssignee(null);
            }}
            selectedDocuments={selectedDocuments}
            selectedAssignee={selectedAssignee}
            setSelectedAssignee={setSelectedAssignee}
            onValidate={handleBulkReassign}
            assignees={assignees}
          />
        )}

        {isModalOpen && (
          <EditModal
            isOpen={isModalOpen}
            onClose={closeModal}
            editingDocument={editingDocument}
            newDocument={newDocument}
            setNewDocument={setNewDocument}
            formErrors={formErrors}
            setFormErrors={setFormErrors}
            tagsInput={tagsInput}
            setTagsInput={setTagsInput}
            onAddTag={handleAddTag}
            onRemoveTag={handleRemoveTag}
            onSubmit={handleSubmit}
            documentTypes={documentTypes}
            documentStatuses={documentStatuses}
            assignees={assignees}
            getWorkflowStep={getWorkflowStep}
            getWorkflowProgress={getWorkflowProgress}
          />
        )}

        {isHistoryModalOpen && (
          <HistoryModal
            isOpen={isHistoryModalOpen}
            onClose={closeHistoryModal}
            documentVersions={documentVersions}
            onCompare={handleCompareVersions}
            onRestore={handleRestoreVersion}
            formatDateTime={formatDateTime}
            statusClass={statusClass}
          />
        )}

        {diffViewerOpen && versionsToCompare && (
          <DiffViewer
            key={`diff-${versionsToCompare.old.id}-${versionsToCompare.new.id}`}
            oldVersion={versionsToCompare.old}
            newVersion={versionsToCompare.new}
            onClose={() => {
              setDiffViewerOpen(false);
              setVersionsToCompare(null);
            }}
          />
        )}
      </Suspense>
    </div>
  );
};

export default Documents;